 1→import { DIMENSION_DEFAULT_OFFSET } from '@/domain/defaults';
 2→import { TOOLS } from '@/editor/tools';
 3→import { createDimensionFigure } from '@/annotations/dimensions';
 4→
 5→export default function DimensionPreview({ toolState, activeTool }) {
 6→  if (activeTool !== TOOLS.DIMENSION) return null;
 7→  if (!toolState.dimensionStartPoint || !toolState.dimensionPreviewPoint) return null;
 8→
 9→  const figure = createDimensionFigure({
10→    id: 'dimension-preview',
11→    startPoint: toolState.dimensionStartPoint,
12→    endPoint: toolState.dimensionPreviewPoint,
13→    mode: 'aligned',
14→    offset: toolState.dimensionPreviewOffset ?? DIMENSION_DEFAULT_OFFSET,
15→    source: 'preview',
16→  });
17→
18→  if (!figure) return null;
19→
20→  return (
21→    <g style={{ pointerEvents: 'none' }}>
22→      {figure.extensionLines.map((line, index) => (
23→        <line
24→          key={`preview-ext-${index}`}
25→          x1={line.start.x}
26→          y1={line.start.y}
27→          x2={line.end.x}
28→          y2={line.end.y}
29→          stroke="var(--color-selection)"
30→          strokeWidth={1}
31→          strokeDasharray="6 3"
32→          vectorEffect="non-scaling-stroke"
33→        />
34→      ))}
35→      <line
36→        x1={figure.lineStart.x}
37→        y1={figure.lineStart.y}
38→        x2={figure.lineEnd.x}
39→        y2={figure.lineEnd.y}
40→        stroke="var(--color-selection)"
41→        strokeWidth={1.5}
42→        strokeDasharray="6 3"
43→        vectorEffect="non-scaling-stroke"
44→      />
45→      {figure.arrowheads.map((arrow, index) => (
46→        <polyline
47→          key={`preview-arrow-${index}`}
48→          points={`${arrow.left.x},${arrow.left.y} ${arrow.tip.x},${arrow.tip.y} ${arrow.right.x},${arrow.right.y}`}
49→          fill="none"
50→          stroke="var(--color-selection)"
51→          strokeWidth={1.2}
52→          vectorEffect="non-scaling-stroke"
53→        />
54→      ))}
55→      <text
56→        x={figure.text.position.x}
57→        y={figure.text.position.y}
58→        textAnchor="middle"
59→        dominantBaseline="middle"
60→        fill="var(--color-selection)"
61→        fontSize={140}
62→        fontFamily="var(--font-blueprint)"
63→        transform={`rotate(${figure.text.angle}, ${figure.text.position.x}, ${figure.text.position.y})`}
64→      >
65→        {figure.text.value}
66→      </text>
67→    </g>
68→  );
69→}
