 1→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 2→
 3→export default function WallRenderer({ walls, columns }) {
 4→  return (
 5→    <g className="walls">
 6→      {walls.map(wall => {
 7→        const outline = getWallRenderData(wall, columns || []).outline;
 8→        const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 9→        return (
10→          <polygon
11→            key={wall.id}
12→            data-id={wall.id}
13→            data-type="wall"
14→            points={points}
15→            fill="var(--color-wall-fill)"
16→            stroke="var(--color-wall-stroke)"
17→            strokeWidth={1}
18→            vectorEffect="non-scaling-stroke"
19→          />
20→        );
21→      })}
22→    </g>
23→  );
24→}
