1→import { buildAnnotationScene } from '@/annotations/scene';
2→import BlueprintAnnotationLayer from './BlueprintAnnotationLayer';
3→
4→export default function AnnotationRenderer({ floor }) {
5→  const scene = buildAnnotationScene(floor);
6→
7→  return <BlueprintAnnotationLayer dimensions={scene.dimensions} tags={scene.tags} />;
8→}
