  1→import { columnOutline } from '@/geometry/columnGeometry';
  2→import { getBeamRenderData } from '@/geometry/beamGeometry';
  3→import { getStairRenderData } from '@/geometry/stairGeometry';
  4→import { getSlabRenderData } from '@/geometry/slabGeometry';
  5→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  6→import { getManualAnnotationFigure } from '@/annotations/scene';
  7→
  8→const HANDLE_SIZE = 8; // px, will use vectorEffect
  9→
 10→function WallSelection({ wall, columns, zoom }) {
 11→  const outline = getWallRenderData(wall, columns || []).outline;
 12→  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
 13→  const handleR = HANDLE_SIZE / zoom;
 14→
 15→  return (
 16→    <g>
 17→      <polygon
 18→        points={points}
 19→        fill="var(--color-selection-fill)"
 20→        stroke="var(--color-selection)"
 21→        strokeWidth={2}
 22→        strokeDasharray="6 3"
 23→        vectorEffect="non-scaling-stroke"
 24→      />
 25→      {/* Endpoint handles */}
 26→      <rect
 27→        data-handle="start"
 28→        x={wall.start.x - handleR / 2}
 29→        y={wall.start.y - handleR / 2}
 30→        width={handleR}
 31→        height={handleR}
 32→        fill="white"
 33→        stroke="var(--color-selection)"
 34→        strokeWidth={2}
 35→        vectorEffect="non-scaling-stroke"
 36→        style={{ cursor: 'move' }}
 37→      />
 38→      <rect
 39→        data-handle="end"
 40→        x={wall.end.x - handleR / 2}
 41→        y={wall.end.y - handleR / 2}
 42→        width={handleR}
 43→        height={handleR}
 44→        fill="white"
 45→        stroke="var(--color-selection)"
 46→        strokeWidth={2}
 47→        vectorEffect="non-scaling-stroke"
 48→        style={{ cursor: 'move' }}
 49→      />
 50→    </g>
 51→  );
 52→}
 53→
 54→export default function SelectionOverlay({ selectedId, selectedType, floor, zoom }) {
 55→  if (!selectedId || !floor) return null;
 56→
 57→  if (selectedType === 'slab') {
 58→    const slab = floor.slab;
 59→    const renderData = slab?.id === selectedId ? getSlabRenderData(slab) : null;
 60→    if (!renderData) return null;
 61→
 62→    const handleR = HANDLE_SIZE / zoom;
 63→    return (
 64→      <g>
 65→        <polygon
 66→          points={renderData.points}
 67→          fill="var(--color-selection-fill)"
 68→          stroke="var(--color-selection)"
 69→          strokeWidth={2}
 70→          strokeDasharray="6 3"
 71→          vectorEffect="non-scaling-stroke"
 72→        />
 73→        {renderData.outline.map((point, index) => (
 74→          <rect
 75→            key={`${point.x}-${point.y}-${index}`}
 76→            data-handle="slab-vertex"
 77→            data-index={index}
 78→            x={point.x - handleR / 2}
 79→            y={point.y - handleR / 2}
 80→            width={handleR}
 81→            height={handleR}
 82→            fill="white"
 83→            stroke="var(--color-selection)"
 84→            strokeWidth={2}
 85→            vectorEffect="non-scaling-stroke"
 86→            style={{ cursor: 'move' }}
 87→          />
 88→        ))}
 89→      </g>
 90→    );
 91→  }
 92→
 93→  if (selectedType === 'wall') {
 94→    const wall = floor.walls.find(w => w.id === selectedId);
 95→    if (!wall) return null;
 96→    return <WallSelection wall={wall} columns={floor.columns || []} zoom={zoom} />;
 97→  }
 98→
 99→  if (selectedType === 'annotation') {
100→    const figure = getManualAnnotationFigure(floor, selectedId);
101→    if (!figure) return null;
102→    return (
103→      <g>
104→        {figure.extensionLines.map((line, index) => (
105→          <line
106→            key={`annotation-ext-${index}`}
107→            x1={line.start.x}
108→            y1={line.start.y}
109→            x2={line.end.x}
110→            y2={line.end.y}
111→            stroke="var(--color-selection)"
112→            strokeWidth={2}
113→            strokeDasharray="6 3"
114→            vectorEffect="non-scaling-stroke"
115→          />
116→        ))}
117→        <line
118→          x1={figure.lineStart.x}
119→          y1={figure.lineStart.y}
120→          x2={figure.lineEnd.x}
121→          y2={figure.lineEnd.y}
122→          stroke="var(--color-selection)"
123→          strokeWidth={2}
124→          strokeDasharray="6 3"
125→          vectorEffect="non-scaling-stroke"
126→        />
127→      </g>
128→    );
129→  }
130→
131→  if (selectedType === 'door') {
132→    const door = floor.doors.find(d => d.id === selectedId);
133→    if (!door) return null;
134→    const wall = floor.walls.find(w => w.id === door.wallId);
135→    if (!wall) return null;
136→    // Highlight parent wall subtly
137→    const outline = getWallRenderData(wall, floor.columns || []).outline;
138→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
139→    return (
140→      <polygon
141→        points={points}
142→        fill="none"
143→        stroke="var(--color-selection)"
144→        strokeWidth={2}
145→        strokeDasharray="6 3"
146→        vectorEffect="non-scaling-stroke"
147→      />
148→    );
149→  }
150→
151→  if (selectedType === 'beam') {
152→    const beam = (floor.beams || []).find(b => b.id === selectedId);
153→    if (!beam) return null;
154→    const renderData = getBeamRenderData(beam, floor.columns || []);
155→    if (!renderData) return null;
156→    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
157→    return (
158→      <polygon
159→        points={points}
160→        fill="var(--color-selection-fill)"
161→        stroke="var(--color-selection)"
162→        strokeWidth={2}
163→        strokeDasharray="6 3"
164→        vectorEffect="non-scaling-stroke"
165→      />
166→    );
167→  }
168→
169→  if (selectedType === 'stair') {
170→    const stair = (floor.stairs || []).find(entry => entry.id === selectedId);
171→    if (!stair) return null;
172→    const renderData = getStairRenderData(stair);
173→    if (!renderData) return null;
174→    const points = renderData.outline.map(p => `${p.x},${p.y}`).join(' ');
175→    return (
176→      <polygon
177→        points={points}
178→        fill="var(--color-selection-fill)"
179→        stroke="var(--color-selection)"
180→        strokeWidth={2}
181→        strokeDasharray="6 3"
182→        vectorEffect="non-scaling-stroke"
183→      />
184→    );
185→  }
186→
187→  if (selectedType === 'window') {
188→    const win = floor.windows.find(w => w.id === selectedId);
189→    if (!win) return null;
190→    const wall = floor.walls.find(w => w.id === win.wallId);
191→    if (!wall) return null;
192→    const outline = getWallRenderData(wall, floor.columns || []).outline;
193→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
194→    return (
195→      <polygon
196→        points={points}
197→        fill="none"
198→        stroke="var(--color-selection)"
199→        strokeWidth={2}
200→        strokeDasharray="6 3"
201→        vectorEffect="non-scaling-stroke"
202→      />
203→    );
204→  }
205→
206→  if (selectedType === 'column') {
207→    const column = (floor.columns || []).find(c => c.id === selectedId);
208→    if (!column) return null;
209→    const outline = columnOutline(column);
210→    const points = outline.map(p => `${p.x},${p.y}`).join(' ');
211→    const handleR = HANDLE_SIZE / zoom;
212→    return (
213→      <g>
214→        <polygon
215→          points={points}
216→          fill="var(--color-selection-fill)"
217→          stroke="var(--color-selection)"
218→          strokeWidth={2}
219→          strokeDasharray="6 3"
220→          vectorEffect="non-scaling-stroke"
221→        />
222→        {outline.map((p, i) => (
223→          <rect
224→            key={i}
225→            x={p.x - handleR / 2}
226→            y={p.y - handleR / 2}
227→            width={handleR}
228→            height={handleR}
229→            fill="white"
230→            stroke="var(--color-selection)"
231→            strokeWidth={2}
232→            vectorEffect="non-scaling-stroke"
233→            style={{ cursor: 'move' }}
234→          />
235→        ))}
236→      </g>
237→    );
238→  }
239→
240→  if (selectedType === 'room') {
241→    const room = floor.rooms.find(r => r.id === selectedId);
242→    if (!room?.points?.length) return null;
243→    const points = room.points.map(p => `${p.x},${p.y}`).join(' ');
244→    return (
245→      <polygon
246→        points={points}
247→        fill="none"
248→        stroke="var(--color-selection)"
249→        strokeWidth={2}
250→        strokeDasharray="6 3"
251→        vectorEffect="non-scaling-stroke"
252→      />
253→    );
254→  }
255→
256→  return null;
257→}
