 11→function createTag(id, textLines, position, options = {}) {
 12→  const lines = textLines.filter(Boolean);
 13→  if (!lines.length) return null;
 14→
 15→  return {
 16→    id,
 17→    type: 'tag',
 18→    sourceType: options.sourceType ?? null,
