 32→      columnCenter(column),
 33→      { sourceType: 'column', sourceId: column.id }
 34→    ))
 35→    .filter(Boolean);
 36→}
 37→
 38→function buildBeamTags(beams = [], columns = []) {
 39→  return beams
 40→    .map((beam, index) => {
 41→      const renderData = getBeamRenderData(beam, columns || []);
 42→      if (!renderData) return null;
 43→      return createTag(
 44→        `beam-tag-${beam.id}`,
 45→        [`B${index + 1}`],
 46→        renderData.midpoint,
 47→        { sourceType: 'beam', sourceId: beam.id }
 48→      );
 49→    })
 50→    .filter(Boolean);
