 53→function buildRoomTags(rooms = []) {
 54→  return rooms
 55→    .map((room, index) => createTag(
 56→      `room-tag-${room.id}`,
 57→      [room.name?.trim() || `R${index + 1}`, formatRoomArea(room)],
 58→      room.labelPosition,
 59→      { sourceType: 'room', sourceId: room.id }
 60→    ))
 61→    .filter(Boolean);
 62→}
 63→
 64→function buildDoorTags(doors = [], walls = []) {
 65→  return doors
 66→    .map((door, index) => {
 67→      const wall = walls.find((entry) => entry.id === door.wallId);
 68→      if (!wall) return null;
 69→      const info = doorOutlineOnWall(wall, door);
 70→      const offset = scale(perpendicular(wallDirection(wall)), wall.thickness / 2 + 180);
 71→      return createTag(
 72→        `door-tag-${door.id}`,
 73→        [`D${index + 1}`],
 74→        add(info.center, offset),
 75→        { sourceType: 'door', sourceId: door.id }
