 1→import { TOOLS } from '@/editor/tools';
 2→import { COLUMN_WIDTH, COLUMN_DEPTH } from '@/domain/defaults';
 3→import { columnOutline } from '@/geometry/columnGeometry';
 4→
 5→export default function ColumnPreview({ toolState, activeTool }) {
 6→  if (activeTool !== TOOLS.COLUMN) return null;
 7→  if (toolState.previewX == null || toolState.previewY == null) return null;
 8→
 9→  const preview = {
10→    x: toolState.previewX,
11→    y: toolState.previewY,
12→    width: COLUMN_WIDTH,
13→    depth: COLUMN_DEPTH,
14→    rotation: 0,
15→  };
16→
17→  const outline = columnOutline(preview);
18→  const points = outline.map(p => `${p.x},${p.y}`).join(' ');
19→
20→  return (
21→    <polygon
22→      points={points}
23→      fill="rgba(160, 160, 160, 0.3)"
24→      stroke="var(--color-selection)"
25→      strokeWidth={2}
26→      strokeDasharray="4 2"
27→      vectorEffect="non-scaling-stroke"
28→      style={{ pointerEvents: 'none' }}
29→    />
30→  );
31→}
