 1→import { TOOLS } from '@/editor/tools';
 2→
 3→function previewPoints(toolState) {
 4→  const points = toolState.slabPoints || [];
 5→  if (!points.length) return [];
 6→  if (!toolState.slabPreviewPoint) return points;
 7→  return [...points, toolState.slabPreviewPoint];
 8→}
 9→
10→export default function SlabPreview({ toolState, activeTool }) {
11→  if (activeTool !== TOOLS.SLAB) return null;
12→
13→  const points = previewPoints(toolState);
14→  const committedPoints = toolState.slabPoints || [];
15→  if (!points.length) return null;
16→
17→  return (
18→    <g style={{ pointerEvents: 'none' }}>
19→      {points.length >= 2 && (
20→        <polyline
21→          points={points.map((point) => `${point.x},${point.y}`).join(' ')}
22→          fill={points.length >= 3 ? 'rgba(127, 143, 166, 0.08)' : 'none'}
23→          stroke="var(--color-selection)"
24→          strokeWidth={28}
25→          strokeDasharray="120 60"
26→          vectorEffect="non-scaling-stroke"
27→        />
28→      )}
29→      {committedPoints.map((point, index) => (
30→        <circle
31→          key={`${point.x}-${point.y}-${index}`}
32→          cx={point.x}
33→          cy={point.y}
34→          r={60}
35→          fill={index === 0 ? 'var(--color-accent)' : 'var(--color-selection)'}
36→          vectorEffect="non-scaling-stroke"
37→        />
38→      ))}
39→    </g>
40→  );
41→}
